const express = require('express');
const fs = require('fs');
const path = require('path');
const morgan = require('morgan');
const winston = require('winston');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const logDir = path.join(__dirname, 'logs');
fs.mkdirSync(logDir, { recursive: true });

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(({ timestamp, level, message }) => `${timestamp} ${level}: ${message}`)
  ),
  transports: [
    new winston.transports.File({ filename: path.join(logDir, 'app.log') }),
    new winston.transports.File({ filename: path.join(logDir, 'audit.log') }),
    new winston.transports.Console()
  ]
});

morgan.token('username', (req) => (req.headers['x-username'] || req.query.username || (req.body && req.body.username) || 'anonymous'));
morgan.token('ip', (req) => req.headers['x-forwarded-for'] || req.socket.remoteAddress || '');
morgan.token('custom', (req) => req.headers['x-custom-header'] || '');
morgan.token('ua', (req) => req.headers['user-agent'] || '');

app.use(
  morgan(':date[iso] :method :url :status :response-time ms ip=:ip user=:username custom=:custom ua=":ua"', {
    stream: {
      write: (line) => logger.info(line.trim())
    }
  })
);

app.post('/audit', (req, res) => {
  const username = req.body.username || req.query.username || req.headers['x-username'] || 'anonymous';
  const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || '';
  const customHeader = req.headers['x-custom-header'] || '';
  const action = req.body.action || 'unknown';
  const details = req.body.details || '';
  const note = req.body.note || '';

  const msg =
    `AUDIT username=${username} ip=${ip} custom=${customHeader} ` +
    `action=${action} details=${details} note=${note} ` +
    `headers=${JSON.stringify(req.headers)} body=${JSON.stringify(req.body)}`;

  logger.info(msg);

  res.json({ ok: true });
});

app.post('/echo', (req, res) => {
  const message = req.body.message || '';
  logger.info(`ECHO message=${message}`);
  res.json({ message });
});

